const body = $json.body ?? $json;
const reviewId = body.reviewId || body.id;
const replyText = (body.replyText || body.text || '').trim();
const sentBy = body.sentBy || 'dashboard';
if (!reviewId || !replyText) throw new Error('reviewId ve replyText gerekli');

const sbBase = ($env.SUPABASE_URL || 'http://host.docker.internal:54321').replace(/\/$/, '');
const sbKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const sbH = { apikey: sbKey, Authorization: `Bearer ${sbKey}`, 'Content-Type': 'application/json', Prefer: 'return=representation' };

const updated = await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${sbBase}/rest/v1/google_reviews?id=eq.${reviewId}`,
  headers: sbH,
  body: {
    draft_reply: replyText,
    status: 'published',
  },
  json: true,
});

// Google Business Profile API bağlanınca burada otomatik yayınlanacak (MVP: panel onayı + kayıt)
return [{ json: { ok: true, review: updated[0] || null, sentBy, note: 'Yanıt kaydedildi. Google İşletme panelinden de yayınlayabilirsiniz.' } }];
